    Arrow(x=V('i', default=0), y=1, angle=Arrow.UP)
)

water = []

def clear_water():
    while len(water)>0:
        water.pop().delete()

class Bar(Rect):
    def __init__(self, idx:int):
        super().__init__(
            x=idx, y=V(f'-heights[{idx}]'),
            height=V(f'1+heights[{idx}]'),
            color=(40,130,20),
            animate=False,z=-1)
        self.idx = idx
        main_panel.add(self)

    def on_drag(self, x: int, y: int, drag_type: str):
        clear_water()
        if drag_type == 'start':
            self.color = (40,80,160)
        if drag_type == 'mid':
            self.color = (180,130,60)
        if drag_type == 'end':
            self.color = (40,130,20)
        heights[self.idx] = max(-y, 0)

for i, h in enumerate(heights):
    Bar(idx=i)

btn = Rect(x=5, y=2, width=4, color=(40,100,200))
def retrap_rain(x: int, y: int):
    clear_water()
    trap_rain()
btn.on_click = retrap_rain

main_panel.add(
    btn, Label(label='trap rain', x=6, y=2, width=2))
# @end

trap_rain()
